DROP TABLE IF EXISTS `post_stats`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `post_stats` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `type` tinyint NOT NULL DEFAULT '0',
  `object_id` bigint NOT NULL COMMENT '对象ID',
  `stats` json NOT NULL COMMENT '点赞统计数据，格式：{"1-1":{"once": 5, "twice": 3, "helpful": 2}, ...}',
  `stat_year` int NOT NULL COMMENT '统计年份',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_type_object_year` (`type`,`object_id`,`stat_year`),
  KEY `idx_stat_year` (`stat_year`),
  KEY `idx_type_object` (`type`,`object_id`)
) ENGINE=InnoDB AUTO_INCREMENT=128 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='每年点赞统计表';
